mapper.select:
SELECT p.id, p.user_id, u.display_name, u.avatar_url, p.content, p.created_at, p.updated_at
FROM posts p
JOIN users u ON p.user_id = u.id
WHERE p.id < #{cursor}
ORDER BY p.id DESC
LIMIT #{limit}

SELECT COUNT(*) FROM posts p
JOIN follows f ON f.followee_id = p.user_id
WHERE f.follower_id = #{userId} AND p.id > #{sinceId}
